import{_ as a,c as n,o as t,ag as e}from"./chunks/framework.ELrfyV9R.js";const d=JSON.parse('{"title":"给不会编程的人讲清楚：Git 到底有什么用？","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2025/2016-01-16-git.md","filePath":"ai/2025/2016-01-16-git.md","lastUpdated":1773928509000}'),i={name:"ai/2025/2016-01-16-git.md"};function p(l,s,o,r,g,c){return t(),n("div",null,s[0]||(s[0]=[e(`<h1 id="给不会编程的人讲清楚-git-到底有什么用" tabindex="-1">给不会编程的人讲清楚：Git 到底有什么用？ <a class="header-anchor" href="#给不会编程的人讲清楚-git-到底有什么用" aria-label="Permalink to &quot;给不会编程的人讲清楚：Git 到底有什么用？&quot;">​</a></h1><h2 id="不写代码也该懂的工具-git-其实是一瓶后悔药" tabindex="-1">不写代码也该懂的工具：Git，其实是一瓶后悔药 <a class="header-anchor" href="#不写代码也该懂的工具-git-其实是一瓶后悔药" aria-label="Permalink to &quot;不写代码也该懂的工具：Git，其实是一瓶后悔药&quot;">​</a></h2><p>git 可以说是程序员的必备工具，但它并不是只有程序员才需要。在当前Vibe Coding不仅仅为了程序员而设计的情况下，很多对文件比如word ppt excel、md、txt等众多文件编辑领域，由于在AI的加持下，它的变化太多了，有时候随便聊聊，可能文件中的内容就变了，但是有时候又像回看之前的版本。就变得毫无章法了。这里就跟程序员的代码类似，程序员只要提交过，就可以随时进行追溯查看。</p><p>你看，程序员都可以吃**“后悔药”**，我们普通人为什么不可以呢？</p><p>既然要深入讲**“后悔药”<strong>这个点，那我们就把 Git 想象成一瓶</strong>“药效极其强大，不但能治病还能预防的神奇后悔药”**。</p><p>普通的撤销（Ctrl+Z）只能让你退回几步，一旦软件关了、或者电脑重启了，后悔药就失效了。</p><p>而 Git 这瓶后悔药，有以下 <strong>4 种不同维度的吃法</strong>，专治各种早知今日，何必当初：</p><hr><h3 id="第一种吃法-定点穿越药-存档回滚" tabindex="-1">第一种吃法：定点穿越药（存档回滚） <a class="header-anchor" href="#第一种吃法-定点穿越药-存档回滚" aria-label="Permalink to &quot;第一种吃法：定点穿越药（存档回滚）&quot;">​</a></h3><p><strong>专治：</strong> <em>“哎呀！手贱把昨天写好的那段最精彩的剧情删了，而且已经保存覆盖了！”</em></p><p>我们平时写文档，点击“保存”，旧的内容就被新的覆盖了，<strong>旧的就死了</strong>，找不回来了。</p><p>但在 Git 的世界里，并没有“覆盖”这个概念，只有“叠加”。</p><ul><li>每次你操作Git 的保存（提交），它不是覆盖旧文件，而是给当前所有文件的状态<strong>拍了一张快照</strong>，并生成一个编号。</li><li><strong>药效：</strong> 一个月后，你发现今天改的内容全是垃圾，想找回一个月前的版本。你只需要告诉 Git：“我要吃那颗编号为 X 的后悔药”。</li><li><strong>结果：</strong> 哪怕中间你改了一万次，Git 也能瞬间把你带回到一个月前那个下午的状态，连标点符号都不差。</li></ul><h3 id="第二种吃法-成分分析药-差异对比" tabindex="-1">第二种吃法：成分分析药（差异对比） <a class="header-anchor" href="#第二种吃法-成分分析药-差异对比" aria-label="Permalink to &quot;第二种吃法：成分分析药（差异对比）&quot;">​</a></h3><p><strong>专治：</strong> <em>“我觉得现在的版本不对劲，但我忘了到底改了哪里，也不记得原来的版本是啥样了。”</em></p><p>很多时候，我们的后悔不是“全盘推翻”，而是“想不起来”。比如你觉得文章读起来变别扭了，但不知道是哪句话的问题。</p><ul><li><strong>药效：</strong> Git 这颗药吃下去，它会给你一副**“红绿眼镜”**。</li><li><strong>结果：</strong> 它会把“现在的你”和“昨天的你”放在左右两边对比,或者上下。</li><li>你删掉的字，它用<strong>红色</strong>标出来。</li><li>你新增的字，它用<strong>绿色</strong>标出来。</li><li>你一眼就能看到：“哦！原来我把这句关键的形容词给删了！”然后只把这一句抓回来就行，不用整个文件回退。</li></ul><h3 id="第三种吃法-处方说明书-提交日志" tabindex="-1">第三种吃法：处方说明书（提交日志） <a class="header-anchor" href="#第三种吃法-处方说明书-提交日志" aria-label="Permalink to &quot;第三种吃法：处方说明书（提交日志）&quot;">​</a></h3><p><strong>专治：</strong> <em>“这行奇怪的代码（或这段文字）是谁写的？为什么要这么写？我是脑子进水了吗？”</em></p><p>几个月后，你看到自己写的一段东西，可能会感到莫名其妙，后悔当初没写个备注。</p><ul><li><strong>药效：</strong> Git 强制要求你在每次存“后悔药”的时候，写一张**“病情描述”**（也就是备注，比如：<em>“删除了第一段，因为客户说太啰嗦”</em>）。</li><li><strong>结果：</strong> 一年后的你，看着这行被删掉的字发呆时，翻开 Git 的“病历本”，上面清楚地写着你当时的理由。你就会释怀：“哦，原来是客户要求的，那没事了。”——<strong>它治好了你“不明不白”的后悔。</strong></li></ul><h3 id="第四种吃法-试错安慰剂-分支隔离" tabindex="-1">第四种吃法：试错安慰剂（分支隔离） <a class="header-anchor" href="#第四种吃法-试错安慰剂-分支隔离" aria-label="Permalink to &quot;第四种吃法：试错安慰剂（分支隔离）&quot;">​</a></h3><p><strong>专治：</strong> <em>“我想大改一下，但万一改废了，原来的也回不来了，所以我不敢动。”</em></p><p>这种后悔叫做“因为害怕而没敢去尝试”的后悔。</p><ul><li><strong>药效：</strong> Git 允许你把当前的完美版本**“冷冻”<strong>起来，然后复制一个一模一样的</strong>“克隆体”**给你去折腾。</li><li><strong>结果：</strong> 你在克隆体上随便乱改，改得天翻地覆。</li><li><strong>改废了？</strong> 没事，一键销毁克隆体，把冷冻的本体解冻，就像什么都没发生过。</li><li><strong>改好了？</strong> 太棒了，把克隆体的内容吸收到本体里。</li><li><strong>作用：</strong> 它让你在做任何危险操作前，都拥有一颗<strong>绝对兜底的后悔药</strong>，让你敢于去“作死”。</li></ul><h3 id="准备吧" tabindex="-1">准备吧 <a class="header-anchor" href="#准备吧" aria-label="Permalink to &quot;准备吧&quot;">​</a></h3><p>上面简单介绍了git的伟大作用，让我们来切实的体验一下吧</p><p>1、首先安装git，安装包地址：<a href="https://git-scm.com/install/windows%EF%BC%8C%E4%B8%80%E7%9B%B4%E9%BB%98%E8%AE%A4%E4%B8%8B%E4%B8%80%E6%AD%A5%E5%B0%B1%E5%8F%AF%E4%BB%A5%E3%80%82" target="_blank" rel="noreferrer">https://git-scm.com/install/windows，一直默认下一步就可以。</a></p><p>2、然后再装个可视化工具，<a href="https://github.com/gitextensions/gitextensions/releases/tag/v6.0.5" target="_blank" rel="noreferrer">https://github.com/gitextensions/gitextensions/releases/tag/v6.0.5</a></p><p>3、如果你无法下载也可以直接在评论区留言，我会单独把安装包发给你。</p><p>4、安装好之后，有一个问题，我们的东西到底是存到哪里呢？这里也就是需要一个远程仓库。 可以选择Github 这个当然懂得都懂。也可以选择码云 <a href="https://gitee.com/" target="_blank" rel="noreferrer">https://gitee.com/</a> 这个国内的也不错。当然也可以选择阿里的<a href="https://codeup.aliyun.com" target="_blank" rel="noreferrer">https://codeup.aliyun.com</a>。 当然这些都是免费的哈。</p><p>先来验证一下</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// window下 使用快捷键 Win + R 打开运行</span></span>
<span class="line"><span>git --version</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 如果出现类似的字符串说明安装成功</span></span>
<span class="line"><span>git version 2.52.0.windows.1</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// git extensions 也是一直默认下一步即可。</span></span></code></pre></div><p>然后生成密钥</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ssh-keygen -t rsa -C &quot;你的邮箱&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 然后连续回车三次，使用默认设置，不用设置密码即可</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 然后到Windows: C:\\Users\\你的用户名\\.ssh\\id_rsa.pub</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 将id_rsa.pub文件中的内容复制到你的远程仓库的SSH公钥设置中即可。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 运行命令进行测试是否成功</span></span>
<span class="line"><span>ssh -T git@gitee.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 再在gitee.com上创建一个仓库</span></span>
<span class="line"><span></span></span>
<span class="line"><span>点击新建仓库</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>填写仓库名称，路径，仓库介绍，选择开源或者私有，然后创建即可</span></span>
<span class="line"><span></span></span>
<span class="line"><span>然后初始化一下仓库</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>现在不写文章，帮我写一个工作流或者skil我用它来提交我当前这个项目到代码仓库</span></span>
<span class="line"><span></span></span>
<span class="line"><span>直接给我创建一个工作流</span></span></code></pre></div><p>看到提交上去了 初步大功告成了</p><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><p>如果把人生比作写代码： 普通人的生活是<strong>单行道</strong>，走错了只能硬着头皮走下去。 用 Git 的人，生活全是<strong>存档点</strong>。</p><ul><li>只要你<strong>存了档</strong>（Commit），你就永远有退路。</li><li>无论你犯了多大的错，Git 都能递给你一杯水和一颗药，跟你说：<strong>“没关系，我们要不回上周五那个版本重新来？”</strong></li></ul>`,41)]))}const u=a(i,[["render",p]]);export{d as __pageData,u as default};
